import{bQ as i,aL as a,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"内存与性能","description":"","frontmatter":{},"headers":[],"relativePath":"05.Redis/04-内存与性能.md","filePath":"05.Redis/04-内存与性能.md","lastUpdated":null}'),d={name:"05.Redis/04-内存与性能.md"};function h(l,s,n,p,k,o){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="内存与性能" tabindex="-1">内存与性能 <a class="header-anchor" href="#内存与性能" aria-label="Permalink to &quot;内存与性能&quot;">​</a></h1><p>Redis 性能问题通常从几个方向切进去：内存用到了多少、淘汰策略是什么、有没有大 key 或热 key、慢日志里有什么命令、缓存有没有挡住下游压力、以及系统层的 CPU/磁盘/网络是否正常。</p><h2 id="一、内存分析" tabindex="-1">一、内存分析 <a class="header-anchor" href="#一、内存分析" aria-label="Permalink to &quot;一、内存分析&quot;">​</a></h2><h3 id="内存总量视角" tabindex="-1">内存总量视角 <a class="header-anchor" href="#内存总量视角" aria-label="Permalink to &quot;内存总量视角&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span></span></code></pre></div><p>关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>used_memory</code></td><td>Redis 分配器统计的已用内存（不含内存碎片）</td></tr><tr><td><code>used_memory_rss</code></td><td>操作系统看到的该进程实际占用的物理内存（含碎片）</td></tr><tr><td><code>mem_fragmentation_ratio</code></td><td><code>used_memory_rss / used_memory</code>，大于 1 表示有碎片</td></tr><tr><td><code>maxmemory</code></td><td>配置的内存上限，0 表示不限制</td></tr></tbody></table><p><code>used_memory</code> 和 <code>used_memory_rss</code> 不一样是正常的。Redis 释放 key 后内存不一定立刻还给操作系统——jemalloc 会保留一部分内存池以备再用。<code>mem_fragmentation_ratio</code> 长期大于 1.5 说明碎片比较严重。比如 <code>used_memory</code> 稳在 4GB 左右，<code>used_memory_rss</code> 却涨到 8GB，刚好业务每天批量删除又写入大量短生命周期 key，这种更像内存碎片；如果 <code>used_memory</code> 自己也一直涨，<code>db0:keys</code> 同时增加，就要先按真实数据增长排查。碎片率一直在涨时，重启实例可以重置（但重启期间不可用，且 AOF/RDB 恢复需要时间）。</p><h3 id="key-空间视角" tabindex="-1">key 空间视角 <a class="header-anchor" href="#key-空间视角" aria-label="Permalink to &quot;key 空间视角&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keyspace</span></span></code></pre></div><p>输出类似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>db0:keys=120000,expires=90000,avg_ttl=3600000</span></span></code></pre></div><ul><li><code>keys</code> —— 当前 DB 里的 key 总数</li><li><code>expires</code> —— 其中设置了过期时间的 key 数量</li><li><code>avg_ttl</code> —— 这些带过期时间的 key 的平均剩余存活时间（毫秒）</li></ul><p>如果 <code>keys</code> 很大但 <code>expires</code> 很小，说明大部分 key 没有过期时间。这些永久 key 可能是配置数据、计数器等有意为之的，也可能是遗忘的缓存——后者会慢慢消耗内存。</p><h2 id="二、maxmemory-和淘汰策略" tabindex="-1">二、maxmemory 和淘汰策略 <a class="header-anchor" href="#二、maxmemory-和淘汰策略" aria-label="Permalink to &quot;二、maxmemory 和淘汰策略&quot;">​</a></h2><p><code>maxmemory</code> 是 Redis 使用内存的上限。达到上限后，<code>maxmemory-policy</code> 决定怎么处理新写入：</p><table tabindex="0"><thead><tr><th>策略</th><th>行为</th><th>适合什么</th></tr></thead><tbody><tr><td><code>noeviction</code></td><td>不淘汰，写入直接报错</td><td>不能接受任何数据被自动删除</td></tr><tr><td><code>allkeys-lru</code></td><td>所有 key 中淘汰最近最少使用的</td><td>纯缓存用途，所有数据都可以丢</td></tr><tr><td><code>volatile-lru</code></td><td>只在设了过期时间的 key 中淘汰</td><td>永久数据 + 缓存混合</td></tr><tr><td><code>allkeys-random</code></td><td>所有 key 中随机淘汰</td><td>访问模式均匀的缓存</td></tr><tr><td><code>volatile-ttl</code></td><td>淘汰 TTL 最短的 key</td><td>希望保留长 TTL 的缓存</td></tr></tbody></table><p>查看淘汰是否在发生：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> evicted_keys</span></span></code></pre></div><p><code>evicted_keys</code> 持续增长说明内存已经触顶，Redis 在按策略踢 key。缓存场景里这不一定不正常——<code>allkeys-lru</code> 下这是预期行为。但如果 Redis 里存的是业务状态（计数器、会话），<code>evicted_keys &gt; 0</code> 就是在丢数据，需要扩内存或者排查 key 是否有不合理的增长。</p><p>注意区分 <code>evicted_keys</code> 和 <code>expired_keys</code>：前者是因为内存满了被 maxmemory 策略踢掉的，后者是因为 TTL 到期被过期机制删掉的。统计口径完全不同。</p><h2 id="三、过期策略的实际行为" tabindex="-1">三、过期策略的实际行为 <a class="header-anchor" href="#三、过期策略的实际行为" aria-label="Permalink to &quot;三、过期策略的实际行为&quot;">​</a></h2><p>Redis 删除过期 key 靠两种机制配合：</p><ul><li><strong>惰性删除</strong>：访问 key 时检查，过期就删</li><li><strong>定期删除</strong>：后台每秒多次随机抽样，删掉其中过期的</li></ul><p>这意味着：key 到期后不一定会被立刻删除，没被访问到的过期 key 会等到定期扫描才清理。大量 key 集中在同一秒过期时（比如整点设置的缓存），定期删除可能短时间消耗明显 CPU。给 TTL 加一点随机值可以打散过期时间：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基础 300 秒，加 0-60 秒随机抖动，避免大量 key 同时过期</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ttl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$((</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">300</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RANDOM</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 61</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:user:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ttl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><h2 id="四、缓存穿透、击穿和雪崩" tabindex="-1">四、缓存穿透、击穿和雪崩 <a class="header-anchor" href="#四、缓存穿透、击穿和雪崩" aria-label="Permalink to &quot;四、缓存穿透、击穿和雪崩&quot;">​</a></h2><p>这三个问题经常被混淆，但成因不同：</p><table tabindex="0"><thead><tr><th>问题</th><th>发生了什么</th><th>处理方向</th></tr></thead><tbody><tr><td>缓存穿透</td><td>查询的数据本来就不存在，缓存永远不命中，每次都查后端</td><td>空值缓存、参数校验、布隆过滤器</td></tr><tr><td>缓存击穿</td><td>某个热点 key 过期，瞬间大量请求同时回源</td><td>互斥回源、后台定时刷新热点、逻辑过期</td></tr><tr><td>缓存雪崩</td><td>大量 key 同时过期或 Redis 整体不可用</td><td>随机 TTL、分批预热、降级限流</td></tr></tbody></table><p><strong>缓存穿透</strong>：数据库里没有这条记录，缓存也不会存它。攻击者或 bug 可以用不存在的 ID 反复查询，每次请求都穿透缓存打到数据库。处理方式是缓存一个短期的&quot;空结果&quot;：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查不到的数据也缓存一个空标记，短 TTL，防止同一个不存在的 ID 反复打库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:user:404</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;__NULL__&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span></span></code></pre></div><p>布隆过滤器是另一种处理方式——在查缓存之前先问布隆过滤器&quot;这个 key 可能存在吗&quot;，如果返回&quot;不存在&quot;就直接返回，不用查缓存也不用查数据库。</p><p><strong>缓存击穿</strong>：热点 key 过期瞬间，大量请求同时发现缓存没了，一起去查数据库重建。用 Redis 锁让只有一个请求回源，其他等结果：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lock_value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uuidgen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lock:rebuild:user:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$lock_value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OK</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 拿到锁，负责回源重建缓存</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;rebuild cache from database&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 没拿到锁，说明有别的请求在重建，短暂等待或走降级逻辑</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;waiting for cache rebuild&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p>锁的过期时间要覆盖回源最大耗时。如果回源本身就很慢（比如查一张大表），锁过期后重建还没完成，第二个请求拿到新锁也会回源——这就是缓存的&quot;击穿传导&quot;。</p><p><strong>缓存雪崩</strong>：大量 key 同时过期，或者 Redis 挂了，大量请求直接冲击后端。打散 TTL 是基础操作；Redis 主从或 Cluster 可以降低单点不可用的风险；应用侧的限流和降级是最后一道防线。</p><p>三种问题可以同时出现——比如 Redis 挂了导致雪崩，重启后热点 key 又集中过期造成击穿。处理时要分清是哪个环节先出问题。</p><h2 id="五、bigkey" tabindex="-1">五、bigkey <a class="header-anchor" href="#五、bigkey" aria-label="Permalink to &quot;五、bigkey&quot;">​</a></h2><p>bigkey 是指 value 很大或成员很多的 key——不是按字节绝对大小定义，而是看对操作的影响。一个 List 有 100 万条元素、一个 Hash 有 10 万个 field、一个 String 存了几 MB 的 JSON，都可以算 bigkey。</p><p>bigkey 的风险：</p><table tabindex="0"><thead><tr><th>风险</th><th>具体影响</th></tr></thead><tbody><tr><td>阻塞主线程</td><td>删除大集合、<code>HGETALL</code> 大 Hash、<code>LRANGE 0 -1</code> 大 List——都是 O(n)</td></tr><tr><td>网络带宽</td><td>一次返回大量数据，网卡被打满</td></tr><tr><td>内存不均衡</td><td>Cluster 中单个 slot 占过大，迁移慢</td></tr><tr><td>复制和持久化</td><td>fork 时的写时复制压力更大</td></tr></tbody></table><p>扫描 bigkey：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bigkeys</span></span></code></pre></div><p>这个命令通过抽样统计来估算每种数据类型中最大的 key。它是抽样的，不是全量精确的，且扫描过程中会消耗 CPU。适合低峰巡检，不适合高峰期跑。</p><p>查看单个 key 的内存占用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MEMORY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> USAGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big:key</span></span></code></pre></div><p>删除大 key 时，<code>DEL</code> 在主线程释放内存——如果 key 里有很多元素或很大 value，主线程会阻塞在这个操作上。Redis 4.0 之后用 <code>UNLINK</code> 异步删除——标记删除后后台线程释放内存，主线程几乎不受影响：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> UNLINK</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big:key</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 异步删除，不阻塞主线程</span></span></code></pre></div><h2 id="六、热-key" tabindex="-1">六、热 key <a class="header-anchor" href="#六、热-key" aria-label="Permalink to &quot;六、热 key&quot;">​</a></h2><p>热 key 是访问特别集中的 key。它让单个 Redis 实例或 Cluster 分片成为瓶颈。表现是：单实例 CPU 高但 QPS 并不特别大（请求集中少数命令）、某个 Cluster 分片的连接数和负载明显高于其他分片。</p><p>检测热 key，Redis 自身提供的工具有限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hotkeys</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 需要 maxmemory-policy 设为 LFU 相关策略才有效</span></span></code></pre></div><p><code>MONITOR</code> 可以看实时命令流，但生产环境谨慎使用——<code>MONITOR</code> 把每条命令都打印出来，高流量时会拖慢 Redis 并且暴露敏感数据。更常见的排查方式是从应用日志、代理层（ProxySQL/Twemproxy）统计或客户端侧采样。</p><p>处理热 key 的常见方向：</p><table tabindex="0"><thead><tr><th>做法</th><th>适用场景</th></tr></thead><tbody><tr><td>本地缓存（应用内存）</td><td>读多写少的热点配置，变化频率低</td></tr><tr><td>key 拆分（如 <code>key:0</code> ~ <code>key:N</code>）</td><td>计数或集合类的热点，随机路由到不同 key</td></tr><tr><td>加随机过期</td><td>避免过期时集中回源</td></tr><tr><td>预热</td><td>发布或活动前把热点数据提前写进去</td></tr><tr><td>限流</td><td>回源压力太大时保护后端</td></tr></tbody></table><h2 id="七、慢日志" tabindex="-1">七、慢日志 <a class="header-anchor" href="#七、慢日志" aria-label="Permalink to &quot;七、慢日志&quot;">​</a></h2><p>Redis 慢日志记录执行时间超过阈值的命令。注意：记录的是命令实际执行时间，不包括网络传输和客户端排队。</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>slowlog-log-slower-than 10000   # 10ms，单位微秒。默认 10000（=10ms），0 表示记录所有命令，负数表示不记录</span></span>
<span class="line"><span>slowlog-max-len 128             # 最多保留 128 条。默认 128，队列满后最旧的记录被丢弃</span></span></code></pre></div><p><code>slowlog-log-slower-than</code> 设为 0 会让每条命令都进慢日志——性能开销和日志量都很大，只适合临时排查。<code>slowlog-max-len</code> 只影响内存中保留的记录数，不影响性能。</p><p>查看：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SLOWLOG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 最近 10 条慢命令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SLOWLOG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LEN</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 当前慢日志条数</span></span></code></pre></div><p>常见出现在慢日志里的命令类型：</p><table tabindex="0"><thead><tr><th>命令</th><th>为什么慢</th></tr></thead><tbody><tr><td><code>KEYS *</code> 或带通配的 <code>KEYS</code></td><td>遍历整个键空间，O(n)</td></tr><tr><td><code>HGETALL</code> 大 Hash</td><td>返回所有 field-value，O(n)</td></tr><tr><td><code>SMEMBERS</code> 大 Set</td><td>返回所有成员，O(n)</td></tr><tr><td><code>LRANGE 0 -1</code> 大 List</td><td>读取整个列表，O(n)</td></tr><tr><td>大 key 的 <code>DEL</code></td><td>主线程释放大量内存</td></tr><tr><td><code>SINTER</code>/<code>SUNION</code> 大集合</td><td>运算量和集合大小成正比</td></tr><tr><td><code>ZRANGE</code> 大 Sorted Set</td><td>遍历跳表</td></tr></tbody></table><h2 id="八、pipeline" tabindex="-1">八、Pipeline <a class="header-anchor" href="#八、pipeline" aria-label="Permalink to &quot;八、Pipeline&quot;">​</a></h2><p>Pipeline 让客户端一次发送多条命令，再批量读回响应——减少网络往返次数（RTT）。适合大量独立的小命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;SET k1 v1\\r\\nSET k2 v2\\r\\nSET k3 v3\\r\\n&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pipe</span></span></code></pre></div><p>Pipeline 不是事务——中间某条命令失败不会回滚前面的，后续命令仍会继续执行。批量写入时要控制每批的大小：一批塞太多命令会让 Redis 的输出缓冲区膨胀，客户端也可能因为一次接收太多响应而超时。</p><h2 id="九、延迟排查" tabindex="-1">九、延迟排查 <a class="header-anchor" href="#九、延迟排查" aria-label="Permalink to &quot;九、延迟排查&quot;">​</a></h2><p>客户端侧延迟探测：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --latency</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --latency-history</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 持续记录延迟变化</span></span></code></pre></div><p>Redis 内部的延迟事件分析：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LATENCY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LATEST</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 最近延迟事件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LATENCY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DOCTOR</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 延迟诊断报告</span></span></code></pre></div><p>延迟变高时，几个方向要同时看：慢日志里有什么命令在执行、<code>INFO persistence</code> 里是否在进行 BGSAVE/AOF 重写（fork 导致的抖动）、磁盘 <code>iostat -x 1</code> 的 <code>await</code> 是否异常（AOF fsync 卡住）、<code>INFO stats</code> 里 <code>evicted_keys</code> 是否在增长（淘汰消耗 CPU）。Redis 延迟很少是&quot;Redis 本身变慢了&quot;，通常是某个具体操作在抢占 CPU 或磁盘。</p>`,73)])])}const y=i(d,[["render",h]]);export{c as __pageData,y as default};
